if условие:
    # код выполняется если условие истинно

Важно: отступы обязательны! Код внутри if должен иметь отступ (обычно 4 пробела).

if условие:
    # код если истина
else:
    # код если ложь

if условие1:
    # код если условие1 истинно
elif условие2:
    # код если условие2 истинно
else:
    # код если все условия ложны

Можно использовать сколько угодно elif.

ru.codeExample:
age = 18

if age < 13:
    print('Ребёнок')
elif age < 18:
    print('Подросток')
elif age < 60:
    print('Взрослый')
else:
    print('Пожилой')

# Вложенные условия
temperature = 25
if temperature > 20:
    if temperature > 30:
        print('Жарко!')
    else:
        print('Тепло')
else:
    print('Холодно')

