if age < 13:
    print('Child')
elif age < 18:
    print('Teenager')
elif age < 60:
    print('Adult')
else:
    print('Senior')

# Nested conditions
temperature = 25
if temperature > 20:
    if temperature > 30:
        print('Hot!')
    else:
        print('Warm')
else:
    print('Cold')

