sections.text:
Позволяет передать любое количество позиционных аргументов:

def sum_all(*args):
    return sum(args)

sum_all(1, 2, 3)  # 6
sum_all(1, 2, 3, 4, 5)  # 15

Позволяет передать любое количество именованных аргументов:

def print_info(**kwargs):
    for key, value in kwargs.items():
        print(f'{key}: {value}')

print_info(name='Алекс', age=25)

ru.codeExample:
# Параметры по умолчанию
def power(base, exp=2):
    return base ** exp

print(power(3))      # 9
print(power(3, 3))   # 27

# *args
def multiply(*numbers):
    result = 1
    for num in numbers:
        result *= num
    return result

print(multiply(2, 3, 4))  # 24

# **kwargs
def create_user(**info):
    user = {}
    for key, value in info.items():
        user[key] = value
    return user

user = create_user(name='Алекс', age=25, city='Москва')
print(user)

