sections.text:
public - атрибут (доступен везде)
_protected - один подчёркивание (для внутреннего использования)
__private - два подчёркивания (скрыт)

@property
def name(self):
    return self._name

@name.setter
def name(self, value):
    self._name = value

ru.codeExample:
class BankAccount:
    def __init__(self, balance):
        self.__balance = balance  # приватный

    @property
    def balance(self):
        return self.__balance

    def deposit(self, amount):
        if amount > 0:
            self.__balance += amount

    def __str__(self):
        return f'Баланс: {self.__balance}'

    def __add__(self, other):
        return BankAccount(self.__balance + other.__balance)

account = BankAccount(1000)
account.deposit(500)
print(account)  # Баланс: 1500

